;BACKUP3/ASM - Backup By Class;;	Find highest available memory page;	LD	HL,0		;Set up to get HIGH$	LD	B,L	@@HIGH$	INC	HL		;Find highest available	DEC	H		;  memory page	LD	A,H	LD	(DOFIL06+1),A	;Save for later testing	LD	(DOFIL08+1),A	LD	(LSTBUF1+1),A	LD	A,0C9H	LD	(PMTDST1),A	;Ignore dest disk test	CALL	PMTDST		;Prompt dest drive;;	Calculate mamximum free space per dest disk type;	LD	A,(IY+7)	;P/u # heads & sect/trk	LD	B,A		;Save heads	AND	1FH		;Mask all but sectors	LD	C,A	INC	C		;Adj for zero offset	XOR	B		;Get # of heads	RLCA	RLCA			;  in bits 0-2	RLCA	INC	A		;Adj to 0 offset	LD	B,A		;Init loop counter	XOR	A		;Init sector count to 0	ADD	A,C		;Multiply # sectors/track	DJNZ	$-1		;  x # of heads/cyl	LD	L,A	LD	H,0		;Xfer to 16-bit reg	JR	NC,NMXSEC	;Go if not 256 sect	INC	H		;  else set to 256NMXSEC	BIT	5,(IY+4)	;If 2-sided diskette	JR	Z,$+3	ADD	HL,HL		;  double the # of sectors	LD	C,(IY+6)	;P/u # cyls & adjust for	DEC	C		;  BOOT & DIR	@@MUL16			;Calc total records	LD	H,L		;Results to HL	LD	L,A	LD	(SIZSAV+1),HL	;Save for later;;	Read the BOOT sector of dest disk;	LD	DE,1		;Track 0, sector 1	LD	HL,BUF2$	;Disk buffer area	CALL	RDSEC		;Read the sector	JP	NZ,EXIT3	;Quit on read error	LD	A,(BOOTST$)	;Locn of boot step rate	LD	L,A	LD	A,(HL)		;Get the step rate in	AND	3		;  bits 0 and 1	LD	(BSCLS+1),A	;Save for later	LD	A,(BUF2$+2)	;P/u dir cyl	LD	(IY+9),A	;Stuff into DCT;;	Check id type byte;	CALL	CKSWDD;;	If a system backup, then check the GAT & HIT;	LD	A,(PRMTBL$+SYSRSP)	OR	A		;P/u SYS parm response	JP	Z,CLSBU5	;  and skip next if not SYS;;	If already a SYSTEM disk, don't check BOOT space;	IF	@MOD2	CALL	PMTDST		;Get dest data;	LD	A,(IY+3)	;Get DCT data	AND	28H		;Bit 5/3	CP	20H		;8" floppy?	JR	NZ,SETSYS2	;Go if not	LD	A,(IY+4)	;Get data	AND	50H		;Bit 6/4	CP	40H		;DD not alien?SETSYS2	LD	D,0		;Cyl 0 if not	JR	NZ,$+3		;Go if system	INC	D		;Sysinfo on cyl 1	ENDIF;	LD	HL,HITBUF	;Set disk buffer	LD	E,2		;  and sector 2;;	Mod II save sysinfo sector for later check;	IF	@MOD2	LD	(CKPROT2),DE	;Save cyl/sect	ENDIF;	IF	@MOD4	CALL	RDSEC		;Read the sysinfo sector	JP	NZ,EXIT3	;QUit on read error	LD	A,(HITBUF+0C0H)	;P/u & test the SYSTEM	INC	A		;  disk byte. If already	LD	D,(IY+9)	JP	Z,CLSBU01	;  a system disk, bypass	ENDIF;	IF	@MOD2;	LD	D,(IY+9)	;P/u dir cyl;	ENDIF;	LD	E,L		;Set sector 0, dir trk	CALL	RDSEC		;Read the GAT	CP	6		;Expect error 6	LD	A,20		;Init "GAT read error	JP	NZ,EXIT3	;Quit on any other error;	IF	@MOD4	LD	B,0		;Need no more	BIT	3,(IY+3)	;  if rigid drive	JR	NZ,SETSYS	;NZ = rigid	ENDIF;;	Check GAT byte on Mod2/12	IF	@MOD2	LD	L,0CDH	BIT	7,(HL)	LD	L,0	JP	Z,CLSBU01	;Go if system disk	ENDIF;;	If ALIEN or NOT 8" space is OK;	IF	@MOD2	LD	A,(CKPROT2+1)	OR	A	JR	Z,SETSYS	;Go if not	ENDIF;;	Mod II must have track 0 fully available;	IF	@MOD2	LD	A,(HITBUF+60H)	;Track 0 lockout data	OR	1		;Boot/sys allocation	CP	(HL)		;Anything here?	JP	NZ,NOTSYS	;Yes, cannot use!	ENDIF;;	Mod II must have 16 sectors available on cyl 1;	IF	@MOD2	INC	HL		;Point to cyl 1	LD	B,3		;2 grans SD or DD	ENDIF;;	Check to be sure additional grans needed for boot;	are not already allocated;	IF	@MOD4	LD	B,2		;If 8" SDEN or DDEN, then	ENDIF;	BIT	5,(IY+3)	;  need gran 1	JR	NZ,$+4	LD	B,6		;5" needs grans 1 & 2	LD	A,(HL)		;P/u GAT byte for BOOT	AND	B		;  & ck for needed space	JR	NZ,NOTSYS	;Go if no free space	LD	A,(HL)		;Reserve the GAT space	OR	B	LD	(HL),A;;	Mod II must make force locked/used cyl 0;	IF	@MOD2	LD	A,-1		;Init	LD	L,0		;Reset to beginning	LD	(HL),A		;Allocate cyl 0	LD	L,60H		;Lockout table	LD	(HL),A		;Lockout cyl 0	ENDIF;;;	Mask the config byte "data/system" disk bit;SETSYS	LD	L,0CDH		;Point to config byte	RES	7,(HL)		;  & show system disk	CALL	WRGAT;;	Adjust the allocation info for BOOT/SYS;CLSBU0	LD	E,2		;Read the directory	CALL	RDSEC		;  sector containing	CP	6		;  BOOT/SYS record	LD	A,17		;Init "dir read error	JP	NZ,EXIT3	INC	B		;Code to 7 3 1	INC	B		;Code to 8 4 2	SRA	B		;Code to 4 2 1	SRA	B		;Code to 2 1 0;	IF	@MOD2	LD	A,(CKPROT2+1)	OR	A	JR	Z,CLSBU01	ENDIF;;	Mod II must force BOOT/SYS to new cyl 1;	IF	@MOD2CLSBU00	LD	L,16H		;Cylinder start	LD	(HL),1		;Force cyl 1	ENDIF;	LD	L,17H		;Point to gran alloc	LD	(HL),B		;Reset alloc	LD	L,14H		;Point to ERN	LD	(HL),16		;Update # BOOT records	LD	L,0	CALL	WRSYS		;Write dir sector back	LD	A,18		;Init "dir write error	JP	NZ,EXIT3	;Exit if so;;	If OLD entered No SYS file check needed;CLSBU01	LD	A,(OLDPRM$)	;Check for OLD entered	OR	A	JR	NZ,CLSBU5	;Skip SYS setup if so;;;	Now check the HIT positions for /SYS files;	CALL	HITRD		;Read in destination HIT	JP	NZ,EXIT3	LD	DE,SYSDEC	;Pt to SYS file hash codes	EX	DE,HL		;HIT to DE, hash tbl to HL	LD	B,16		;Check 16 DECsCLSBU1	LD	A,(DE)		;If dest spare, stuff	OR	A		;  with source else	JR	NZ,CLSBU2	;  test for match	LD	A,(HL)	LD	(DE),ACLSBU2	CP	(HL)		;Dest match source?	JR	Z,CLSBU3	;Continue if soNOTSYS	LD	HL,NOTSYS$	;Init"Can't make sys disk...	JP	EXIT4		;Display and quitCLSBU3	INC	E		;Bump to next DEC	INC	HL		;  & our table	LD	A,8		;At midpoint?	CP	E	JR	NZ,CLSBU4	;Skip if not	LD	E,20H		;Adjust DEC row #CLSBU4	DJNZ	CLSBU1	LD	D,(IY+9)	;Ok to backup SYSTEM	LD	E,1		;Init to HIT sector	LD	HL,HITBUF	CALL	WRSYS		;Write back dest HIT	LD	A,23		;Init "HIT write error	CALL	Z,HITRD		;Verify if write OK	JP	NZ,EXIT3	;Quit on any error;;	Set up byte 'C0' in SYSINFO sector;	IF	@MOD2	LD	DE,(CKPROT2)	;Get sysinfo sector	LD	E,2		;Force sector 2	ENDIF;	IF	@MOD4	LD	DE,02		;P/u Mod4 SYSINFO sect	ENDIF;;	HL => to HITBUF at this point;	CALL	RDSEC		;Read the sector	LD	L,0C0H		;Point to type flag	LD	(HL),0FFH	;Set it	LD	L,0		;Reset buffer	CALL	WRSEC		; Write it back;CLSBU5	CALL	PMTSRC		;Set up for source disk	CALL	HITRD		;Read source HIT	JP	NZ,EXIT3;;	Start the backup of files;	LD	HL,HITBUF	;Init to start of HIT	JR	SCNH3		;Branch to startOPENIT	DB	'R'!80H		;R2SCNHIT	POP	HL		;Remove top stack entrySCNH1	POP	BC		;Recover DEC posn	LD	H,HITBUF<-8	;HIT buf hi-order	LD	L,B		;  and lo-orderSCNH2	@@CKBRKC		;Check break hit	JP	NZ,BREAK	;Quit if so	LD	A,L		;Get the current DEC posn	ADD	A,20H		;Advance to next file on	LD	L,A		;  this dir sector until	JR	NC,SCNH3	;  end, then go to next	INC	L		;  dir sector in the HIT	BIT	5,L		;Did we go off the end?	JR	Z,SCNH3		;  (ie from 1F to 20)	LD	A,0SETBIT	EQU	$-1	OR	A	JR	Z,TOEXIT1	;If not, all done	CALL	PMTDST		;Get dest DCT in IY	LD	HL,HITBUF	LD	D,(IY+9)	;Get dir cyl	LD	E,L		;Point to GAT sector	CALL	RDSEC		;  & read it	CP	6	LD	A,20		;Init "GAT read error	JP	NZ,EXIT3	LD	L,0CDH		;Point to config byte	SET	4,(HL)	CALL	WRGATTOEXIT1	JP	EXIT1;;	Continue to scan the major loop;SCNH3	LD	A,(HL)		;Is HIT entry spare?	OR	A	JR	Z,SCNH2		;Loop back if so	LD	A,L	AND	0FEH		;Bypass if BOOT or DIR	JR	Z,SCNH2	LD	B,L		;Save DEC	PUSH	BC	CALL	PMTSRC		;Set up for source disk	LD	D,(IY+9)	;P/u DIR cyl	LD	A,B		;Pt to dir sector of	AND	1FH		;  this file	ADD	A,2		;Adj for GAT & HIT	LD	E,A	LD	HL,BUF2$	;Read dir sector	CALL	RDSEC	CP	6		;Proper errcod?	JP	NZ,DIRERR	LD	A,B		;Pt to dir record for	AND	0E0H		;  the source file	LD	L,A	LD	H,BUF2$<-8	;Pt to hi-order dir buf	LD	A,(HL)		;Ignore file if not	LD	(ATTRIB+1),A	;  assigned in directory	BIT	4,A	JR	Z,NODOIT	BIT	7,A		;Ignore file if FXDE	JP	NZ,SCNH1	INC	L		;Bump to DIR+1	LD	A,(MODPRM$)	;Bypass if Mod parm	OR	A		;  not entered	JR	Z,SCNH4	BIT	6,(HL)		;If Mod parm and bit not set	JR	Z,NODOIT	;  skip the file;SCNH4	BIT	4,(HL)		;Check date not current	JR	Z,SCNH4A	LD	A,(SVCTR)	OR	A		;Was date set?	JR	Z,NODOIT	;Bypass if not	INC	A		;Is date current?	JR	Z,NODOIT	;Bypass if not;SCNH4A	DEC	L		;DIR + 0	LD	A,(CLSFLG$)	;P/u CLASS parm byte	BIT	6,(HL)		;Bypass if not SYS file	JR	Z,CKINV	BIT	6,A		;Ok, it is, was SYS used?	JR	Z,NODOIT	;Go if no SYS parm	JR	CKNAM		;  else back it upCKINV	BIT	3,(HL)		;Test if file is INV	JR	Z,CKNAM	BIT	3,A		;File is, want INV files?NODOIT	JP	Z,SCNH1		;Don't want invisiblesCKNAM	LD	A,(SPCFLD$)	;Now test filespec match	CP	' '		;If blank, don't bother	JR	NZ,CKNAM0	;  to match, take it	LD	A,(SPCFLD$+8)	;How about the extension?	CP	' '	JR	Z,SCNH6		;Go if no ext either;;	Test for a filespec match;CKNAM0	PUSH	HL	LD	A,L	ADD	A,5		;Pt to filename in dir	LD	L,A	LD	DE,SPCFLD$	;Pt to user filespec	LD	B,11		;11 char maxCKNAM1	LD	A,(DE)		;P/u user entry	CP	'$'		;Wild card character?	JR	Z,CKNAM2	;Always matches	CP	(HL)		;Same as filespec?	JR	Z,CKNAM2	;Loop if so	CP	' '		;Ignore any further?	JP	NZ,TSTMFLG	;If not blank, no matchCKNAM2	INC	HL		;Match so far	INC	DE	DJNZ	CKNAM1;;	Filespec class matches, check if NOT used;	LD	A,(MFLG$)	;Bypass if a match but	OR	A		;  - exclude given	JP	NZ,SCNHIT	;- was used, skip file	JR	SCNH5;TSTMFLG	LD	A,(MFLG$)	;Ignore if NG match &	OR	A		;  no exclude given	JP	Z,SCNHITSCNH5	POP	HL		;Rcvr ptr to DIR+0SCNH6	PUSH	HL;;	Now check if date matches;	INC	HL		;Pt to date field	CALL	UNPACK		;Alter date for cpr	LD	A,(FTFLG$)	RLCA			;Tst From bit	JR	NC,SCNH7	LD	A,D		;Ignore if date was	OR	E		;  00/00/00 for file	JP	Z,SCNHIT	LD	HL,(FMPAKD$)	;P/u user entry	EX	DE,HL	CALL	CPHLDE		;HL-DE	EX	DE,HL	JP	C,SCNHIT	;Bypass if date range badSCNH7	LD	A,(FTFLG$)	RRCA			;Test TO bit	JR	NC,MATCHES	;Go if no TOPARM else	LD	A,D		;  ck if file is dated	OR	E	JP	Z,SCNHIT	;Bypass if date was 00	LD	HL,(TOPAKD$)	;P/u user's packed date	CALL	CPHLDE		;HL-DE	JP	C,SCNHIT	;Bypass if out of rangeMATCHES	POP	HLDONAM	LD	A,L		;Pt to start of dir rec	AND	0E0H	LD	L,A		;Make sure it's on stack	PUSH	HL	ADD	A,5		;Pt to start of filename	LD	L,A	LD	DE,FCB1$	;Move filename into fcb	LD	B,8		;Init 8 chars for filenameDONAM1	LD	A,(HL)		;P/u a char from the dir	CP	' '		;Space = end of name	JR	Z,DONAM2	LD	(DE),A		;Move char to