1	LD	A,' '		;Write a space	LD	(DE),A	INC	DE	INC	HL		;Advance to date field	EX	DE,HL	LD	(HL),'{'	;Stuff left brace	INC	HL	EX	DE,HL	LD	A,(HL)		;If no date, then skip	OR	A	JR	Z,SCDAT4	;Ignore if no date saved	RRCA			;Has date, get day	RRCA	RRCA	AND	1FH	LD	B,2FH		;Convert day to decimalSCDAT2	INC	B		;  by counting # of 10's	SUB	10		;Sub 10 from day #	JR	NC,SCDAT2	ADD	A,3AH		;Cvrt lo order to ASCII	PUSH	AF		;Save day low order	LD	A,B		;Stuff day hi order	LD	(DE),A	INC	DE		;Bump	POP	AF		;Rcvr lo order day #	LD	(DE),A		;Stuff low order	INC	DE		;Bump pointer to msg	LD	A,'-'	LD	(DE),A		;Stuff '-'	INC	DE		;Pt tO month field	PUSH	HL		;Save DIR ptr	PUSH	AF		;Save separator char	DEC	HL		;Pt to DIR+1 (month+)	LD	A,(HL)		;P/u month etc	AND	0FH		;Strip off flags	DEC	A		;(mon-1)*3 to index	LD	C,A		;   string conversion table	RLCA			;X2	ADD	A,C		;X3	LD	C,A		;Results to BC	LD	B,0	LD	HL,MONTBL	;Ptr to month names	ADD	HL,BC		;Add offset to tbl start	LD	C,3	LDIR			;Move 3-char month	POP	AF	LD	(DE),A	INC	DE		;Advance to year field	POP	HL		;Ptr to DIR+2	LD	C,'8'		;Init for 1980's	LD	A,(DVTEST1)	OR	A	JR	NZ,NEWDT2	;Go if new style	LD	A,(HL)		;Else get old year	AND	7		;Mask it	JR	THERENEWDT2	LD	A,L		;Offset to year	ADD	A,17	LD	L,A		;DIR+19	LD	A,(HL)	AND	1FH		;Mask time	CP	10		;1980's?	JR	C,THERE	LD	C,'9'		;Bump decade	SUB	10	CP	10		;Now must be 0-9	JR	C,THERE	LD	A,9		;  else make 1999THERE	LD	B,A		;Save year offset	LD	A,C		;Stuff decade for dsply	LD	(DE),A	INC	DE	LD	A,B		;Year	ADD	A,'0'		;Make ascii	LD	(DE),A	INC	DESCDAT4	LD	A,3		;Show etx for display	LD	(DE),A	@@DSPLY	FCB1$		;Display filename	@@DSPLY	QMARK$		;" } ? "	LD	HL,(BUFFER$)	;Get user response	LD	BC,3<8		;3 char max	@@KEYIN	JP	C,ABRTBU	;Quit on Break	LD	A,(HL)		;Get the 1st char	RES	5,A		;Strip lc if present	CP	'Y'		;Yes means move the file	JR	Z,CPYMSG	;Go if so;;	Accept 'C' for response to set QUERY=N;	SUB	'C'		;Was response "C"?	JP	NZ,SCNHIT