	AND	7		;Cvrt to ASCII	ADD	A,'0'	LD	(DE),A		; & stuff at filespec end	INC	DE	LD	A,3		;Terminate with ETX	LD	(DE),A	LD	HL,FCB1$	;Copy source fcb to	LD	DE,FCB2$	;  dest fcb	LD	BC,32	LDIR	POP	DE		;Rcvr where source spec	LD	A,(SRCDRV$+1)	;P/u source drive #	AND	7		;Cvrt to ASCII	ADD	A,'0'	LD	(DE),A		;Stuff in dest fcb	RET;;	Routine to extract date from directory;UNPACK	LD	A,(HL)		;P/u DIR+1	AND	0FH		;Remove flags	LD	E,0	LD	D,A		;Split mont to DE	SRL	D	RR	E	INC	HL		;Pt to day	LD	A,(HL)	AND	0F8H		;Mask off year	RRCA			;Bits 2-6	OR	E		;Merge w/month	LD	E,A	LD	A,(DVTEST2)	OR	A		;New style year?	JR	NZ,NEWDT3	;Go if so	LD	A,(HL)		;get old year	AND	7SHFTD	RLCA	RLCA	RLCA			;To bits 3-7	OR	D		;Merge w/month	LD	D,A	RETNEWDT3	LD	A,L	ADD	A,17	LD	L,A		;DIR+19	LD	A,(HL)	AND	1FH	JR	SHFTD;;	Write the GAT back to disk;WRGAT	LD	L,0		;HL to start of buffer	CALL	WRSYS		;Write dir sector	LD	A,21		;Init GAT write error	JP	NZ,EXIT3	;  and quit on error	CALL	VERSEC		;Verify good write	CP	6		;Expect error 6	LD	A,20		;Init GAT read error	JP	NZ,EXIT3	;Quit on any other error	RET;;	Write last buffer if needed;LSTBUF	LD	A,(BUFFER$+1)	;P/u hi order buffer start	CP	H		;Are we there now?	RET	Z		;Back if so, nothing loadedLSTBUF1	LD	A,$-$		;P/u last available page	CP	H		;There now?	RET	Z		;Already written if so	LD	B,H		;Need to write to this page	LD	HL,(BUFFER$)	;P/u buffer startLSTBUF2	LD	(FCB2$+3),HL	;  and put in dest fcb	CALL	GETDST		;Prompt dest	@@VER			;Write with verify	JP	NZ,EXIT3	;Quit on bad write	INC	H		;Bump buffer page	LD	A,H	CP	B		;At the end?	JR	NZ,LSTBUF2	;Loop if more	RET;;	Check if enough space on destination disk;WRERN	LD	A,B		;If ERN = 0, don't	OR	C		; write a ERN	RET	Z	DEC	BC		;Adjust for 0 offset	CALL	GETDST		;Prompt dest	PUSH	DE		;Save fcb pointer	@@POSN			;Position to end	LD	HL,(BUFFER$)	;P/u buffer addr	LD	D,H		;Construct a format	LD	E,L		;  sector of all X'E5's	INC	DE	LD	BC,255	LD	(HL),0E5H	LDIR	POP	DE		;Rcvr fcb ptr	@@VER			;Write with verify	RET	Z		;Ret if no error	CP	27		;Disk Full?	JR	NZ,NOTDF	;No - quit on real error	@@REMOV			;Remove what can't fit	BIT	3,(IY+3)	;Is this a rigid disk?	JR	Z,NOTHARD	;Go if not	BIT	2,(IY+3)	;Shown as Removable?	JR	Z,NOTHARD	;Prompt disk swap if so	LD	HL,FULDRV$	;Prepare disk full error	JR	DOING1NOTHARD	@@FLAGS	BIT	5,(IY+'S'-'A')	;Can't switch while DOing	JR	NZ,DOING	LD	HL,NEWDISK	;"disk full, enter new...	CALL	FLASH	OR	1		;Show switched dest	RETNOTDF	EQU	$	JP	EXIT3		;Error exit;GETSRC	PUSH	BC	LD	DE,FCB1$	;Pt to source FCB	CALL	PMTSRC		;Show source is current	POP	BC		;  for disk I/O	RET;GETDST	PUSH	BC	LD	DE,FCB2$	;Pt to dest FCB	CALL	PMTDST		;Show dest is current	POP	BC		;  for disk I/O	RET;HITRD	LD	D,(IY+9)	;P/u dir cyl of source	LD	E,1		;Read HIT	LD	HL,HITBUF	;Into HIT buffer	CALL	RDSEC	CP	6		;Errcod correct?	LD	A,16H		;Init "HIT read error	RET			;Return w/condition;DOING	LD	HL,DOMSGDOING1	JP	EXIT4;CPYFIL$	DB	29,'Copying file: ',3QUERY	DB	'Backup ',3FULDRV$	DB	'Disk is full ',CRNEWDISK	DB	'Disk is full - Insert new formatted '	DB	'destination disk, <ENTER>',29,3DOMSG	DB	'Disk is full! - Can''t switch '	DB	'while <DO> in effect',CRSIZBIG$	DB	'  File is larger than destination '	DB	'capacity - backup is bypassed',CRNOTSYS$	DB	'Can''t create SYSTEM disk - '	DB	'directory slots in use',CRQMARK$	DB	'} ? ',3MONTBL	DM	'JanFebMarAprMayJunJulAugSepOctNovDec'SYSDEC	DB	0A2H,0C4H,2EH,2FH,2CH,2DH,2AH,2BH	DB	28H,29H,26H,27H,27H,0A7H,26H,0A6H;	DC	64,0		;PATCH space;	ORG	$<-8+1<+8HITBUF	DS	256